// main.ts
var LEGACY_DEFAULT_PROMPT = `\u4F60\u662F LaTeX \u6570\u5B66\u516C\u5F0F\u8F6C\u6362\u5668\u3002\u5C06\u7528\u6237\u7684\u6570\u5B66\u63CF\u8FF0\u8F6C\u6362\u4E3A LaTeX \u4EE3\u7801\u3002
	\u89C4\u5219\uFF1A
	1. \u53EA\u8FD4\u56DE\u7EAF LaTeX \u4EE3\u7801\uFF0C\u4E0D\u8981\u89E3\u91CA
	2. \u4E0D\u8981\u7528 markdown \u4EE3\u7801\u5757\u5305\u88F9
	3. \u4E0D\u8981\u5305\u542B $ \u6216 $$ \u5206\u9694\u7B26
	4. \u4FDD\u6301\u6570\u5B66\u8BED\u4E49\u7684\u51C6\u786E\u6027`;
var LatexAutocompletePlugin = class extends import_obsidian4.Plugin {
  constructor() {
    super(...arguments);
    this.settings = DEFAULT_SETTINGS;
  }
  async onload() {
    await this.loadSettings();
    const commands = latex_commands_default;
    this.registerEditorSuggest(
      new LatexSuggest(this.app, commands, LANG_REGISTRY, () => this.settings)
    );
    const tabHandler = (evt) => {
      if (evt.key === "Tab" && !evt.ctrlKey && !evt.altKey && !evt.metaKey) {
        if (this.handleTab()) {
          evt.preventDefault();
          evt.stopPropagation();
        }
      }
    };
    const doc = window.activeDocument;
    doc.addEventListener("keydown", tabHandler, true);
    this.register(() => doc.removeEventListener("keydown", tabHandler, true));
    this.addSettingTab(
      new LatexAutocompleteSettingTab(
        this.app,
        this,
        this.settings,
        () => this.saveSettings()
      )
    );
  }
  onunload() {
  }
  async loadSettings() {
    this.settings = Object.assign({}, DEFAULT_SETTINGS, await this.loadData());
    if (!this.settings.aiSystemPrompt || this.settings.aiSystemPrompt === LEGACY_DEFAULT_PROMPT) {
      this.settings.aiSystemPrompt = t("defaultPrompt");
    }
  }
  async saveSettings() {
    await this.saveData(this.settings);
  }
  handleTab() {
    var _a;
    if (!this.settings.aiApiKey)
      return false;
    const editor = (_a = this.app.workspace.activeEditor) == null ? void 0 : _a.editor;
    if (!editor)
      return false;
    const cursor = editor.getCursor("head");
    if (!isInMathContext(editor, cursor))
      return false;
    const result = extractPromptText(editor, cursor);
    if (!result)
      return false;
    const notice = new import_obsidian4.Notice(t("notice.generating"), 0);
    callAiApi(result.text, this.settings).then((latex) => {
      editor.replaceRange(latex, result.start, result.end);
      editor.setCursor({
        line: result.start.line,
        ch: result.start.ch + latex.length
      });
      notice.hide();
      new import_obsidian4.Notice(t("notice.generated"), 2e3);
    }).catch((err) => {
      notice.hide();
      new import_obsidian4.Notice(t("notice.aiFail") + String(err), 5e3);
    });
    return true;
  }
};

